() => {
  // Find the accepted answer - it has an "Accepted" note
  const acceptedAnswer = document.querySelector('.answer[answerid="11227902"]');
  // Or find by looking for the accepted checkmark
  const answers = document.querySelectorAll('.answer');
  let accepted = null;
  for (const ans of answers) {
    if (ans.querySelector('.vote-count-post')) {
      const acceptedIcon = ans.querySelector('.icon-checkmark');
      if (acceptedIcon) {
        accepted = ans;
        break;
      }
    }
  }
  if (!accepted) {
    // Try another approach - find the answer with accepted status
    const allAnswers = document.querySelectorAll('[id^="answer-"]');
    for (const ans of allAnswers) {
      const checkmark = ans.querySelector('.✓, .icon-checkmark, [class*="accepted"]');
      if (checkmark || ans.classList.contains('accepted-answer')) {
        accepted = ans;
        break;
      }
    }
  }

  // Count code and pre elements
  if (accepted) {
    const codeElements = accepted.querySelectorAll('code');
    const preElements = accepted.querySelectorAll('pre');
    return {
      codeCount: codeElements.length,
      preCount: preElements.length,
      total: codeElements.length + preElements.length
    };
  }
  return null;
}

