  // Get accepted answer vote count
  const answers = document.querySelectorAll('[id^="answer-"]');
  let acceptedVoteCount = 0;
  let acceptedAuthor = '';
  let totalAnswers = 0;

  // Count total answers
  const heading = document.querySelector('h2:contains("Answer")');
  const answersHeader = document.querySelector('.answers-header h2') || document.querySelector('.answers-subheader h2');
  if (answersHeader) {
    const match = answersHeader.textContent.match(/(\d+)\s+Answer/);
    if (match) totalAnswers = parseInt(match[1]);
  }

  for (const ans of answers) {
    // Check if this is accepted answer
    const checkmark = ans.querySelector('.icon-checkmark');
    if (checkmark) {
      // Get vote count
      const voteCell = ans.querySelector('.vote-count-post');
      if (voteCell) acceptedVoteCount = parseInt(voteCell.textContent.replace(/,/g, ''));

      // Get author
      const authorLink = ans.querySelector('.user-details a');
      if (authorLink) acceptedAuthor = authorLink.textContent;
      break;
    }
  }

  return {
    acceptedVoteCount,
    acceptedAuthor,
    totalAnswers
  };
}

